// Parse challenge from HTML
const html = $input.first().json.data;

// Extract hex values from toNumbers("...")
const regex = /toNumbers\("([a-f0-9]+)\"\)/g;
const matches = [...html.matchAll(regex)];

if (matches.length < 3) {
  throw new Error('Could not find challenge data');
}

return {
  key: matches[0][1],
  iv: matches[1][1],
  data: matches[2][1]
};

// AES Decryption function
const crypto = require('crypto');

const input = $input.first().json;

// Convert hex to buffer
const key = Buffer.from(input.key, 'hex');
const iv = Buffer.from(input.iv, 'hex');
const encrypted = Buffer.from(input.data, 'hex');

// AES-CBC Decrypt
const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);
let decrypted = decipher.update(encrypted);
decrypted = Buffer.concat([decrypted, decipher.final()]);

// Convert to hex for cookie
const cookieValue = decrypted.toString('hex');

return {
  cookie: cookieValue
};

const html = $input.first().json.data;

// Extract response from HTML
const match = html.match(/<div class="response-content">(.*?)<\/div>/s);

return {
  response: match ? match[1].trim() : 'No response found',
  raw_html: html
};
